// WorkspaceBrand
// ──────────────
// Compact brand mark + label used at the start of the workspace top toolbar.
// Two presentation modes — "logomark" (small triangle-style logo, used in
// session workspace) and "wordmark" (logo + label, used in project workspace).
//
// The component is purely presentational; click handling is forwarded to the
// page via the `open-dropdown` emit (parent decides whether to show a popup
// with the project's session list, settings, etc.).
//
// The triangle logo is rendered as an inline SVG so the brand color and
// stroke style stay in lockstep with the surrounding dark glass UI without
// depending on the OiIcon registry (the registry holds a more detailed
// wordmark for the marketing/login pages, which is too large for this
// top-bar use).

<template>
  <button
    type="button"
    class="brand"
    :class="[`brand--${variant}`]"
    :aria-label="`${label} — 打开菜单`"
    :aria-haspopup="true"
    :aria-expanded="dropdownOpen"
    @click="handleClick"
  >
    <span class="brand__mark" aria-hidden="true">
      <!-- Stylised neon triangle that nods to the openimago wordmark -->
      <svg viewBox="0 0 32 32" width="22" height="22" fill="none">
        <defs>
          <linearGradient :id="gradId" x1="4" y1="28" x2="28" y2="4" gradientUnits="userSpaceOnUse">
            <stop offset="0" stop-color="#00E5FF"/>
            <stop offset="0.55" stop-color="#7DD3FC"/>
            <stop offset="1" stop-color="#A78BFA"/>
          </linearGradient>
        </defs>
        <path
          d="M16 4 4 26h24L16 4Z"
          :stroke="`url(#${gradId})`"
          stroke-width="2.2"
          stroke-linejoin="round"
          fill="rgba(0, 240, 255, 0.06)"
        />
        <path
          d="M16 12 10 24h12L16 12Z"
          :stroke="`url(#${gradId})`"
          stroke-width="1.6"
          stroke-linejoin="round"
          opacity="0.65"
        />
        <circle cx="16" cy="20" r="1.6" fill="#A78BFA" />
      </svg>
    </span>
    <span v-if="variant === 'wordmark'" class="brand__label">
      {{ label }}
    </span>
    <span v-if="showChevron" class="brand__chevron" aria-hidden="true">
      <OiIcon name="chevron-down" :size="14" />
    </span>
  </button>
</template>

<script setup lang="ts">
import { computed } from 'vue'
import OiIcon from 'src/components/ui/OiIcon.vue'

// Stable gradient id per component instance so multiple brand buttons
// (top bar + sidebar) don't collide.
const _instanceSeed = Math.floor(Math.random() * 1e6)
const gradId = computed(() => `workspace-brand-grad-${_instanceSeed}`)

withDefaults(defineProps<{
  /** "logomark" — small mark only; "wordmark" — mark + label. */
  variant?: 'logomark' | 'wordmark'
  /** Visible label, e.g. "工作台" or the current project name. */
  label?: string
  /** Whether to render the chevron. */
  showChevron?: boolean
  /** Reflect the parent's open state for aria-expanded. */
  dropdownOpen?: boolean
}>(), {
  variant: 'logomark',
  label: '工作台',
  showChevron: true,
  dropdownOpen: false,
})

const emit = defineEmits<{
  (e: 'open-dropdown'): void
}>()

function handleClick(): void {
  emit('open-dropdown')
}
</script>

